parameters.emailMessage/Subject:
@concat(
  'Escalation: MoM Action Item overdue by ',
  string(coalesce(outputs('Compose_daysPastDue'), 0)),
  ' days'
)

@
if(
  greater(outputs('Compose_daysPastDue'),0),
  concat('Reminder: MoM Action – Overdue By ', string(outputs('Compose_daysPastDue')), ' day(s)'),
  if(
    equals(outputs('Compose_daysPastDue'),0),
    'Reminder: MoM Action – Due today',
    concat('Reminder: MoM Action – Due in ', string(mul(outputs('Compose_daysPastDue'), -1)), ' day(s)')
  )
)

equals:
@or(

  equals(
    toLower(
      trim(
        string(
          coalesce(item()?['ManualReminderTrigger'], '')
        )
      )
    ),
    'yes'
  ),


  and(

  
    or(
      equals(outputs('Compose_daysPastDue'), -2),
      equals(outputs('Compose_daysPastDue'), 0)
    ),

   
    or(
    
      empty(outputs('Compose_LastReminderSent_Parsed')),

     
      greaterOrEquals(
        outputs('Compose_DaysSinceLastReminder'),
        variables('ReminderCooldownDays')
      )
    ),

   
    not(
      empty(
        trim(
          string(
            coalesce(item()?['ResponsibleEmail'], '')
          )
        )
      )
    )

  )
)

Compose_LastReminderSent_Parsed.inputs:
@if(
  empty(items('Apply_to_each')?['LastReminderSent']),
  null,
  if(
    or(
      contains(string(items('Apply_to_each')?['LastReminderSent']), '/'),
      contains(string(items('Apply_to_each')?['LastReminderSent']), '-'),
      contains(string(items('Apply_to_each')?['LastReminderSent']), 'T'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'jan'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'feb'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'mar'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'apr'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'may'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'jun'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'jul'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'aug'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'sep'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'oct'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'nov'),
      contains(toLower(string(items('Apply_to_each')?['LastReminderSent'])),'dec')
    ),

    parseDateTime(
      trim(
        replace(
          string(items('Apply_to_each')?['LastReminderSent']),
          decodeUriComponent('%C2%A0'),
          ' '
        )
      )
    ),

    addSeconds(
      '1899-12-30T00:00:00Z',
      int(
        mul(
          float(
            trim(
              replace(
                replace(
                  replace(
                    replace(
                      replace(
                        string(items('Apply_to_each')?['LastReminderSent']),
                        decodeUriComponent('%C2%A0'), ' '
                      ),
                      ',', ''
                    ),
                    ' ', ''
                  ),
                  '-', ''
                ),
                '—',''
              )
            )
          ),
          86400
        )
      )
    )
  )
)
